import React, { useState, useEffect } from "react";
import api from "../api/api"; // ✅ Usamos tu instancia con el Token
import "bootstrap/dist/css/bootstrap.min.css";
import TicketVenta from "../components/TicketVenta";
import { FaSearch, FaCartPlus, FaCashRegister, FaUser } from "react-icons/fa";

export default function Ventas() {
  const [productos, setProductos] = useState([]);
  const [clientes, setClientes] = useState([]);
  const [busquedaProducto, setBusquedaProducto] = useState("");
  const [productoSeleccionado, setProductoSeleccionado] = useState(null);
  
  // Datos del Cliente
  const [clienteNombre, setClienteNombre] = useState("");
  const [clienteApellido, setClienteApellido] = useState("");
  const [clienteTelefono, setClienteTelefono] = useState("");
  
  const [cantidad, setCantidad] = useState(1);
  const [mensaje, setMensaje] = useState("");
  const [ticket, setTicket] = useState(null);
  const [carrito, setCarrito] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    obtenerProductos();
    obtenerClientes();
  }, []);

  const obtenerProductos = async () => {
    try {
      const res = await api.get("/productos");
      setProductos(res.data);
    } catch (err) { console.error(err); }
  };

  const obtenerClientes = async () => {
    try {
      const res = await api.get("/clientes");
      setClientes(res.data);
    } catch (err) { console.error(err); }
  };

  const buscarProducto = (texto) => {
    setBusquedaProducto(texto);
    const producto = productos.find((p) =>
      (p.nombre || "").toLowerCase().includes(texto.toLowerCase())
    );
    setProductoSeleccionado(producto || null);
  };

  const agregarAlCarrito = () => {
    if (!productoSeleccionado || cantidad <= 0) return;

    const stockActual = Number(productoSeleccionado.stock || 0);
    
    // ⚠️ CRUCIAL: Usamos "ProductID" con mayúsculas porque así lo lee tu backend: p.ProductID
    const prodID = productoSeleccionado._id; 

    if (stockActual < cantidad) {
      setMensaje(`❌ Stock insuficiente (${stockActual})`);
      return;
    }

    const existente = carrito.find((p) => p.ProductID === prodID);

    if (existente) {
      if (existente.Cantidad + cantidad > stockActual) {
        setMensaje("❌ Stock máximo superado");
        return;
      }
      setCarrito(carrito.map((p) => p.ProductID === prodID ? { ...p, Cantidad: p.Cantidad + cantidad } : p));
    } else {
      setCarrito([...carrito, {
        ProductID: prodID, // ✅ Coincide con tu controlador
        Nombre: productoSeleccionado.nombre,
        Cantidad: cantidad, // ✅ Coincide con tu controlador
        PrecioUnitario: productoSeleccionado.precio,
      }]);
    }
    setProductoSeleccionado(null);
    setBusquedaProducto("");
    setCantidad(1);
  };

  const realizarVenta = async () => {
    if (!clienteNombre.trim() || !clienteApellido.trim() || carrito.length === 0) {
      setMensaje("⚠️ Completa los datos y el carrito.");
      return;
    }

    setLoading(true);
    try {
      // Buscamos si el cliente ya existe
      let clienteExistente = clientes.find(
        (c) => (c.nombre || "").toLowerCase() === clienteNombre.toLowerCase() &&
               (c.apellido || "").toLowerCase() === clienteApellido.toLowerCase()
      );

      // ✅ PAYLOAD EXACTO PARA TU CONTROLADOR (registrarVenta)
      const payload = {
        ClienteID: clienteExistente?._id || null, // Si es null, el backend crea el cliente
        Nombre: clienteNombre,
        Apellido: clienteApellido,
        Telefono: clienteTelefono || "",
        productos: carrito.map((p) => ({
          ProductID: p.ProductID, // 👈 Tu backend espera: p.ProductID
          Cantidad: p.Cantidad    // 👈 Tu backend espera: p.Cantidad
        })),
        metodoPago: "efectivo"
      };

      const res = await api.post("/ventas/registrar", payload);

      // Mapeamos la respuesta para que el componente TicketVenta la entienda
      // Tu backend devuelve VentaID, NumeroTicket y Total
      const ticketData = {
        _id: res.data.VentaID,
        NumeroSecuencia: res.data.NumeroTicket,
        Total: res.data.Total,
        Fecha: new Date(),
        NombreCliente: `${clienteNombre} ${clienteApellido}`,
        productos: carrito // Usamos los datos del carrito local para el ticket
      };

      setTicket(ticketData);
      alert("✅ Venta Guardada en Atlas");
      setCarrito([]);
      setClienteNombre("");
      setClienteApellido("");
      setClienteTelefono("");
      obtenerProductos(); // Actualizar stock visualmente
    } catch (err) {
      setMensaje(`❌ Error: ${err.response?.data?.msg || err.message}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container-fluid p-4">
      <div className="row">
        {/* IZQUIERDA: BUSCADOR Y CLIENTE */}
        <div className="col-lg-7">
          <div className="card shadow-sm border-0 p-4 mb-4 rounded-4">
            <h5 className="fw-bold mb-3"><FaCashRegister className="me-2 text-primary" /> Punto de Venta</h5>
            
            <label className="form-label small fw-bold">1. Buscar Producto</label>
            <input type="text" className="form-control mb-3 bg-light border-0" placeholder="Nombre del producto..." value={busquedaProducto} onChange={(e) => buscarProducto(e.target.value)} />

            {productoSeleccionado && (
              <div className="alert alert-primary d-flex justify-content-between align-items-center">
                <div>
                  <strong>{productoSeleccionado.nombre}</strong> <br/>
                  <small>Precio: ${productoSeleccionado.precio} | Stock: {productoSeleccionado.stock}</small>
                </div>
                <div className="d-flex gap-2">
                  <input type="number" className="form-control form-control-sm" style={{width: '60px'}} value={cantidad} onChange={(e)=>setCantidad(Number(e.target.value))} />
                  <button className="btn btn-primary btn-sm" onClick={agregarAlCarrito}><FaCartPlus/></button>
                </div>
              </div>
            )}

            <label className="form-label small fw-bold mt-3">2. Información del Cliente</label>
            <div className="row g-2">
              <div className="col-6"><input className="form-control" placeholder="Nombre" value={clienteNombre} onChange={(e)=>setClienteNombre(e.target.value)} /></div>
              <div className="col-6"><input className="form-control" placeholder="Apellido" value={clienteApellido} onChange={(e)=>setClienteApellido(e.target.value)} /></div>
              <div className="col-12"><input className="form-control" placeholder="Teléfono" value={clienteTelefono} onChange={(e)=>setClienteTelefono(e.target.value)} /></div>
            </div>
            {mensaje && <div className="alert alert-info mt-3">{mensaje}</div>}
          </div>
        </div>

        {/* DERECHA: CARRITO Y TOTAL */}
        <div className="col-lg-5">
          <div className="card shadow-sm border-0 p-4 rounded-4 bg-white h-100">
            <h5 className="fw-bold mb-3 border-bottom pb-2">🛒 Carrito</h5>
            <div className="table-responsive" style={{minHeight: '300px'}}>
              <table className="table table-sm">
                <thead>
                  <tr className="small text-muted">
                    <th>Producto</th>
                    <th>Cant.</th>
                    <th className="text-end">Total</th>
                  </tr>
                </thead>
                <tbody>
                  {carrito.map((p, i) => (
                    <tr key={i}>
                      <td>{p.Nombre}</td>
                      <td>{p.Cantidad}</td>
                      <td className="text-end">${(p.Cantidad * p.PrecioUnitario).toFixed(2)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <div className="border-top pt-3">
              <div className="d-flex justify-content-between fs-3 fw-bold text-success">
                <span>TOTAL:</span>
                <span>${(carrito.reduce((acc, p) => acc + p.Cantidad * p.PrecioUnitario, 0) * 1.12).toFixed(2)}</span>
              </div>
              <button className="btn btn-success w-100 py-3 mt-3 fw-bold rounded-pill shadow" onClick={realizarVenta} disabled={loading || carrito.length === 0}>
                {loading ? "PROCESANDO..." : "CONFIRMAR VENTA"}
              </button>
            </div>
          </div>
        </div>
      </div>

      {ticket && (
        <div className="modal show d-block" style={{ backgroundColor: "rgba(0,0,0,0.6)" }}>
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content border-0 bg-transparent">
              <TicketVenta ticket={ticket} setTicket={setTicket} />
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
